import React, { useState } from "react";
import axios from "axios";

import districtOptions from "../data/district_options.json";
import commodityOptions from "../data/commodity_options.json";

const CropPriceLookup = () => {
    const [district, setDistrict] = useState("");
    const [commodity, setCommodity] = useState("");
    const [prices, setPrices] = useState(null);
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState("");

    const fetchPrices = async () => {
        if (!commodity || !district) {
            setError("Please select both commodity and district.");
            return;
        }

        setLoading(true);
        setError("");

        try {
            const response = await axios.post("http://localhost:5000/api/crops/getPrices", {
                Commodity: commodity,
                District: district,
            });
            setPrices(response.data);
        } catch (err) {
            setError("Failed to fetch price data.");
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="max-w-2xl mx-auto p-8 bg-gradient-to-br from-amber-100 via-green-50 to-orange-100 shadow-2xl rounded-xl border-4 border-amber-800/20">
            <div className="text-center mb-8">
                <h2 className="text-4xl font-bold text-amber-900 mb-2 drop-shadow-lg">🌾 Crop Price Lookup 🌾</h2>
                <p className="text-amber-800/70 text-lg">Find the latest market prices for your crops</p>
            </div>
            
            <div className="space-y-6 bg-white/50 p-6 rounded-lg shadow-inner">
                <div className="space-y-4">
                    <div>
                        <label className="block text-amber-900 font-semibold mb-2">Select Commodity</label>
                        <select 
                            value={commodity} 
                            onChange={(e) => setCommodity(e.target.value)} 
                            className="w-full p-4 border-2 border-amber-200 rounded-lg bg-white text-amber-900 shadow-md focus:ring-2 focus:ring-amber-400 focus:border-amber-400 transition-all duration-300"
                        >
                            <option value="">Choose your crop</option>
                            {commodityOptions.map((item, index) => (
                                <option key={index} value={item}>{item}</option>
                            ))}
                        </select>
                    </div>

                    <div>
                        <label className="block text-amber-900 font-semibold mb-2">Select District</label>
                        <select 
                            value={district} 
                            onChange={(e) => setDistrict(e.target.value)} 
                            className="w-full p-4 border-2 border-amber-200 rounded-lg bg-white text-amber-900 shadow-md focus:ring-2 focus:ring-amber-400 focus:border-amber-400 transition-all duration-300"
                        >
                            <option value="">Choose your district</option>
                            {districtOptions.map((item, index) => (
                                <option key={index} value={item}>{item}</option>
                            ))}
                        </select>
                    </div>
                </div>
                
                <button 
                    onClick={fetchPrices} 
                    className="w-full p-4 bg-amber-700 text-white font-bold rounded-lg shadow-lg hover:bg-amber-800 transition-all duration-300 transform hover:scale-[1.02] active:scale-[0.98]"
                >
                    🔍 Get Market Prices
                </button>
            </div>
            
            {loading && (
                <div className="mt-6 text-center">
                    <p className="text-amber-900 animate-pulse font-medium">Loading market prices...</p>
                </div>
            )}
            
            {error && (
                <div className="mt-6 p-4 bg-red-50 border-2 border-red-200 rounded-lg">
                    <p className="text-red-700 font-semibold text-center">{error}</p>
                </div>
            )}
            
            {prices && (
                <div className="mt-8 p-6 bg-white/80 rounded-xl shadow-xl border-2 border-amber-200">
                    <h3 className="text-2xl font-bold text-amber-900 text-center mb-6">📊 Market Price Details 📊</h3>
                    <div className="grid gap-4 md:grid-cols-2">
                        {prices.map((data, index) => (
                            <div 
                                key={index} 
                                className="p-5 bg-gradient-to-br from-amber-50 to-orange-50 shadow-md rounded-lg border-2 border-amber-200 hover:shadow-lg transition-all duration-300"
                            >
                                <div className="space-y-2">
                                    <p className="font-bold text-amber-900 text-lg">Grade: {data.Grade}</p>
                                    <div className="grid grid-cols-2 gap-2 text-amber-800">
                                        <p><span className="font-semibold">Min Price:</span> ₹{data["Min Price"]}</p>
                                        <p><span className="font-semibold">Max Price:</span> ₹{data["Max Price"]}</p>
                                        <p className="col-span-2"><span className="font-semibold">Modal Price:</span> ₹{data["Modal Price"]}</p>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            )}
        </div>
    );
};

export default CropPriceLookup;
